GetMySellingListings:
query GetMySellingListings($nextPageCursor: String = "", $limit: Int = 20, $sellFasterVariant: String! = "subs_1d_3d") {
  getMySellingItems: fetchMyOfferSellingData(
    data: {limit: $limit, sellFasterSimplificationVariant: $sellFasterVariant, nextPageCursor: $nextPageCursor}
  ) {
    hasPromotedListings
    nextPageCursor
    listings {
      id
      title
      originalTitle
      viewCount
      state
      discussionCount
      photos {
        list {
          url
          __typename
        }
        __typename
      }
      itemActions {
        itemId
        promos {
          subtitleToDisplay
          decoratorToDisplay
          title
          preselected
          promoType
          featureList {
            description
            available
            __typename
          }
          paymentDataWeb {
            priceToDisplay
            priceCurrencyCode
            isFreeTrial
            microunits
            __typename
          }
          __typename
        }
        __typename
      }
      purchasedItemPromos {
        isPromotedPlus: hasActiveSubscription
        isPromoted
        hasExpiredPromos
        expireDate: stackedDate
        __typename
      }
      __typename
    }
    __typename
  }
}

